import { useState, useRef } from "react";

const NGADV_LOGO  = "data:image/png;base64,";
const LAADV_LOGO  = "data:image/png;base64,";
const LAADV_LOGO2 = "data:image/png;base64,";
const BG_OFFICE   = "data:image/jpeg;base64,";

// ─── Dados estáticos ──────────────────────────────────────────────────────────
const ESCRITORIOS = {
  ngadv: { nome: "NGADV", cor: "#1a3a5c", logo: NGADV_LOGO },
  laadv: { nome: "LAADV", cor: "#7c1c1c", logo: LAADV_LOGO },
};

const TIPOS_PECA = [
  "Réplica","Recurso de Apelação","Recurso Inominado","Contestação",
  "Impugnação","Embargos de Declaração","Agravo de Instrumento",
  "Manifestação sobre Laudo","Petição de Emenda à Inicial","Petição Simples","Outro"
];

const MATERIAS = [
  "Direito do Consumidor","Direito Médico e da Saúde","Direito Previdenciário",
  "Direito Administrativo","Direito Empresarial","Planos de Saúde","Energia Elétrica","Outro"
];

const BANCO_PROMPTS = [
  { tipo:"Réplica", materia:"Direito do Consumidor",
    prompt:'Elabore uma réplica à contestação apresentada pelo réu. A empresa alega [ALEGAÇÃO PRINCIPAL]. O autor comprova [PROVA DISPONÍVEL]. Refute cada argumento defensivo com fundamento no CDC. IMPORTANTE: não invente jurisprudências — use apenas teses conhecidas ou solicite pesquisa real antes de citar. Requeira ao final a procedência dos pedidos iniciais.' },
  { tipo:"Recurso de Apelação", materia:"Direito do Consumidor",
    prompt:'Redija recurso de apelação contra sentença que [RESULTADO DA SENTENÇA]. O juiz equivocou-se ao [PONTO DE ERRO]. Demonstre o vício de julgamento com base nos fatos provados nos autos (doc. [X]) e no CDC art. [Y]. ATENÇÃO: não cite números de acórdãos ou súmulas sem que eu os forneça — indique apenas a existência de entendimento consolidado, sem inventar referências.' },
  { tipo:"Embargos de Declaração", materia:"Planos de Saúde",
    prompt:'Oponha embargos de declaração ao acórdão/sentença proferido em [DATA]. Aponte omissão quanto a [PONTO OMITIDO], contradição entre [FUNDAMENTO A] e [FUNDAMENTO B] e obscuridade na parte que trata de [TRECHO]. Requeira integração do julgado com efeito infringente se necessário.' },
  { tipo:"Petição de Emenda à Inicial", materia:"Direito do Consumidor",
    prompt:'Elabore emenda à petição inicial conforme determinado pelo despacho de [DATA]. O juiz apontou [DETERMINAÇÃO]. Corrija o(s) vício(s) indicado(s) e complemente com [INFORMAÇÃO ADICIONAL], mantendo a coerência com os pedidos originais.' },
];

const USUARIOS = [
  { id:1, nome:"Nicolas Gomes",  perfil:"sócio",        escritorio:"ngadv" },
  { id:2, nome:"Luis Albert",    perfil:"sócio",        escritorio:"laadv" },
  { id:3, nome:"Ana Costa",      perfil:"advogado",     escritorio:"ngadv" },
  { id:4, nome:"Pedro Lima",     perfil:"advogado",     escritorio:"laadv" },
  { id:5, nome:"Julia Mendes",   perfil:"estagiario",   escritorio:"ngadv" },
  { id:6, nome:"Carlos Rocha",   perfil:"colaborador",  escritorio:"laadv" },
];

const DASHBOARD_DATA = [
  { usuario:"Ana Costa",    pecas:28, tempoMedio:"42min",  emendas:2, materias:["Direito do Consumidor","Planos de Saúde"] },
  { usuario:"Pedro Lima",   pecas:19, tempoMedio:"55min",  emendas:4, materias:["Planos de Saúde","Energia Elétrica"] },
  { usuario:"Julia Mendes", pecas:11, tempoMedio:"1h12min",emendas:3, materias:["Direito do Consumidor"] },
  { usuario:"Carlos Rocha", pecas:8,  tempoMedio:"1h30min",emendas:1, materias:["Direito Administrativo"] },
];

// ─── Utilitários ──────────────────────────────────────────────────────────────
const FONT_BODY   = '"Cambria", "Georgia", serif';
const FONT_UI     = '"Cambria", "Georgia", serif';

function QualityBadge({ score, msg }) {
  const map = {
    bom:        { bg:"#eafaf0", color:"#1a6e32", label:"BOM" },
    médio:      { bg:"#fff9e6", color:"#8a5e00", label:"MÉDIO" },
    fraco:      { bg:"#fdf0f0", color:"#8a1a1a", label:"FRACO" },
    incompleto: { bg:"#f5f5f5", color:"#555",    label:"INCOMPLETO" },
  };
  const s = map[score] || map.incompleto;
  return (
    <div style={{ marginTop:8, padding:"8px 12px", borderRadius:6, background:s.bg, fontSize:12, color:s.color, fontFamily:FONT_UI }}>
      <strong>Qualidade do contexto: {s.label}</strong> — {msg}
    </div>
  );
}

// ─── Componente principal ─────────────────────────────────────────────────────
export default function LexIA() {
  const [tela,       setTela]       = useState("login");
  const [usuario,    setUsuario]    = useState(null);
  const [aba,        setAba]        = useState("nova");

  // Formulário de nova petição
  const [escritorio,    setEscritorio]    = useState("ngadv");
  const [tipoPeca,      setTipoPeca]      = useState("");
  const [materia,       setMateria]       = useState("");
  const [numProcesso,   setNumProcesso]   = useState("");
  const [parteAutora,   setParteAutora]   = useState("");
  const [parteRe,       setParteRe]       = useState("");
  const [descricao,     setDescricao]     = useState("");
  const [arquivos,      setArquivos]      = useState([]);
  const [pecaGerada,    setPecaGerada]    = useState("");
  const [parecerIA,     setParecerIA]     = useState("");
  const [etapa,         setEtapa]         = useState("form");
  const [qualidade,     setQualidade]     = useState(null);
  const [alertaLider,   setAlertaLider]   = useState(false);
  const [modoGuiado,    setModoGuiado]    = useState(false);
  const [gerandoPeca,   setGerandoPeca]   = useState(false);
  const fileRef = useRef();
  const resultRef = useRef();

  // ── Avaliação de qualidade do prompt ────────────────────────────────────────
  function avaliarPrompt(desc) {
    if (!tipoPeca)                    return { score:"incompleto", msg:"Selecione o tipo de peça.", escalate:false };
    if (!materia)                     return { score:"incompleto", msg:"Selecione a matéria jurídica.", escalate:false };
    if (!parteAutora || !parteRe)     return { score:"incompleto", msg:"Informe as partes do processo.", escalate:false };
    if (!desc || desc.trim().length < 30) return { score:"fraco", msg:"Descrição muito curta. Detalhe os fatos, a parte contrária e o pedido.", escalate:true };
    const kw = ["réu","autor","pedido","contrato","fato","prova","alegou","requereu","sentença","despacho","decisão","cliente","empresa","documento","prazo","tutela"];
    const hits = kw.filter(p => desc.toLowerCase().includes(p)).length;
    if (hits < 2)  return { score:"fraco",  msg:"Contexto vago. Mencione os fatos centrais, o que a parte contrária alegou e o resultado pretendido.", escalate:true };
    if (hits < 5)  return { score:"médio",  msg:"Bom início. Acrescente provas disponíveis e o argumento principal.", escalate:false };
    return           { score:"bom",    msg:"Contexto suficiente para elaborar a peça com qualidade.", escalate:false };
  }

  // ── Geração da peça via API ──────────────────────────────────────────────────
  async function lerArquivos(files) {
    const docs = [];
    for (const file of files) {
      try {
        const arrayBuf = await file.arrayBuffer();
        const b64 = btoa(String.fromCharCode(...new Uint8Array(arrayBuf)));
        const isPDF = file.type === "application/pdf" || file.name.toLowerCase().endsWith(".pdf");
        if (isPDF) {
          docs.push({
            type: "document",
            source: { type: "base64", media_type: "application/pdf", data: b64 },
            title: file.name
          });
        }
        // DOCX: send as base64 document too
        else if (file.name.toLowerCase().endsWith(".docx")) {
          docs.push({
            type: "document",
            source: { type: "base64", media_type: "application/vnd.openxmlformats-officedocument.wordprocessingml.document", data: b64 },
            title: file.name
          });
        }
      } catch(e) {
        console.error("Erro ao ler arquivo:", file.name, e);
      }
    }
    return docs;
  }

  async function gerarPeca() {
    const av = avaliarPrompt(descricao);
    setQualidade(av);
    if (av.escalate)     { setAlertaLider(true); return; }
    if (av.score === "incompleto") return;

    setEtapa("gerando");
    setGerandoPeca(true);
    setPecaGerada(""); setParecerIA("");
    setTimeout(() => resultRef.current?.scrollIntoView({ behavior:"smooth" }), 100);

    const escInfo = ESCRITORIOS[escritorio];

    // ── System prompt com regras rígidas sobre jurisprudência ─────────────────
    const system = `Você é um assistente jurídico especializado do escritório \${escInfo.nome}, atuante em \${materia}.

REGRAS ABSOLUTAS — NUNCA VIOLE:
1. JAMAIS invente, fabrique ou complete números de processos, acórdãos, súmulas ou referências jurisprudenciais. Isso configura fraude processual com risco de multa e responsabilidade disciplinar ao advogado.
2. Se quiser citar jurisprudência, use APENAS uma das três formas abaixo:
   a) Cite uma súmula/tese cujo NÚMERO e ENUNCIADO você tenha certeza absoluta (ex.: Súmula 297 do STJ — conhecida e verificável).
   b) Descreva o entendimento consolidado SEM inventar número: "O STJ possui entendimento pacificado no sentido de que..." 
   c) Indique ao advogado que deve pesquisar: "[INSERIR JURISPRUDÊNCIA APÓS PESQUISA NO PORTAL DO STJ/STF]"
3. Jurisprudência NÃO é obrigatória em toda peça. Omita quando não houver certeza ou quando a lei e os fatos já sustentarem o pedido.
4. Fonte padrão: Cambria 12pt. Recuo esquerdo 3cm, recuo direito 2cm, espaçamento simples, alinhamento justificado.
5. Nunca invente fatos além do que foi informado.`;

    const user = `Processo nº \${numProcesso || "não informado"}
Parte autora: \${parteAutora}
Parte ré: \${parteRe}
Tipo de peça: \${tipoPeca}
Matéria: \${materia}

Contexto e instruções:
\${descricao}

Responda em duas partes claramente separadas:

PARTE 1 — PARECER JURÍDICO (3 a 5 parágrafos):
Analise a situação processual. Indique pontos fortes e fracos da tese. Se houver jurisprudência relevante com a qual você tenha CERTEZA ABSOLUTA (súmula numerada e enunciado exato), mencione. Caso contrário, APENAS sugira ao advogado que pesquise no portal do tribunal competente — nunca invente referências.

PARTE 2 — PEÇA PROCESSUAL COMPLETA:
Elabore a peça com cabeçalho, qualificação das partes, dos fatos, do direito (citando artigos de lei aplicáveis), dos pedidos e fechamento com local, data e espaço para assinatura.`;

    try {
      const res = await fetch("https://api.anthropic.com/v1/messages", {
        method:"POST",
        headers:{ "Content-Type":"application/json" },
        body: JSON.stringify({
          model:"claude-sonnet-4-20250514",
          max_tokens:1000,
          system,
          messages:[{ role:"user", content: arquivos.length > 0
            ? [...(await lerArquivos(arquivos)), { type:"text", text: user }]
            : user
          }]
        })
      });
      const data = await res.json();
      const texto = data.content?.filter(b=>b.type==="text").map(b=>b.text).join("\n") || "Erro ao gerar peça.";

      // Separar PARTE 1 e PARTE 2
      const splitMatch = texto.match(/PARTE\s*2[^\n]*\n/i);
      if (splitMatch) {
        const idx = texto.indexOf(splitMatch[0]);
        setParecerIA(texto.slice(0, idx).replace(/PARTE\s*1[^\n]*\n/i,"").trim());
        setPecaGerada(texto.slice(idx + splitMatch[0].length).trim());
      } else {
        setParecerIA("Análise integrada na peça abaixo.");
        setPecaGerada(texto);
      }
    } catch(e) {
      setPecaGerada("Erro de conexão com a IA. Verifique sua conexão e tente novamente.");
    }
    setGerandoPeca(false);
    setEtapa("resultado");
  }

  function sugerirPrompt() {
    const match = BANCO_PROMPTS.find(p=>p.tipo===tipoPeca && p.materia===materia)
               || BANCO_PROMPTS.find(p=>p.tipo===tipoPeca)
               || BANCO_PROMPTS[0];
    setDescricao(match.prompt);
  }

  function resetForm() {
    setEtapa("form"); setDescricao(""); setPecaGerada(""); setParecerIA("");
    setQualidade(null); setAlertaLider(false); setArquivos([]);
    setNumProcesso(""); setParteAutora(""); setParteRe(""); setTipoPeca(""); setMateria("");
    setModoGuiado(false);
  }

  const escInfo = ESCRITORIOS[escritorio];

  // ═══════════════════════════════════════════════════════════════════════════
  // TELA DE LOGIN
  // ═══════════════════════════════════════════════════════════════════════════
  if (tela === "login") return (
    <div style={{
      minHeight:"100vh", display:"flex", alignItems:"center", justifyContent:"center",
      backgroundImage:`url(\${BG_OFFICE})`, backgroundSize:"cover", backgroundPosition:"center",
      fontFamily:FONT_UI, position:"relative"
    }}>
      {/* overlay escuro sobre a foto */}
      <div style={{ position:"absolute", inset:0, background:"rgba(10,8,6,0.62)" }}/>

      <div style={{ position:"relative", zIndex:1, display:"flex", flexDirection:"column", alignItems:"center", gap:0, width:420 }}>
        {/* Logotipo textual */}
        <div style={{ textAlign:"center", marginBottom:32 }}>
          <div style={{ fontSize:42, fontWeight:700, color:"#fff", letterSpacing:-1, fontFamily:FONT_BODY }}>
            LEX<span style={{ color:"#c8960c" }}>IA</span>
          </div>
          <div style={{ fontSize:11, color:"#c8960c", letterSpacing:5, textTransform:"uppercase", marginTop:2 }}>Grupo 3S · Advocacia Estratégica</div>
          <div style={{ width:60, height:1, background:"#c8960c", margin:"12px auto 0" }}/>
        </div>

        {/* Card de seleção */}
        <div style={{
          background:"rgba(255,255,255,0.06)", backdropFilter:"blur(18px)",
          border:"1px solid rgba(200,150,12,0.3)", borderRadius:16,
          padding:"32px 36px", width:"100%", boxSizing:"border-box"
        }}>
          <div style={{ fontSize:12, color:"rgba(255,255,255,0.5)", marginBottom:20, letterSpacing:1, textTransform:"uppercase" }}>
            Selecione seu perfil
          </div>
          <div style={{ display:"flex", flexDirection:"column", gap:8 }}>
            {USUARIOS.map(u => {
              const cor = ESCRITORIOS[u.escritorio].cor;
              return (
                <button key={u.id} onClick={() => { setUsuario(u); setTela("app"); }} style={{
                  display:"flex", alignItems:"center", gap:14, padding:"12px 16px",
                  border:"1px solid rgba(255,255,255,0.12)", borderRadius:10,
                  background:"rgba(255,255,255,0.05)", cursor:"pointer", textAlign:"left",
                  transition:"all .15s", fontFamily:FONT_UI
                }}
                  onMouseOver={e => { e.currentTarget.style.background="rgba(200,150,12,0.15)"; e.currentTarget.style.borderColor="rgba(200,150,12,0.5)"; }}
                  onMouseOut={e  => { e.currentTarget.style.background="rgba(255,255,255,0.05)"; e.currentTarget.style.borderColor="rgba(255,255,255,0.12)"; }}
                >
                  <div style={{
                    width:38, height:38, borderRadius:"50%", background:cor, flexShrink:0,
                    display:"flex", alignItems:"center", justifyContent:"center",
                    color:"#fff", fontSize:13, fontWeight:700, fontFamily:FONT_BODY
                  }}>
                    {u.nome.split(" ").map(n=>n[0]).join("").slice(0,2)}
                  </div>
                  <div>
                    <div style={{ fontSize:14, fontWeight:600, color:"#fff" }}>{u.nome}</div>
                    <div style={{ fontSize:11, color:"rgba(255,255,255,0.45)", textTransform:"capitalize" }}>
                      {u.perfil} · {ESCRITORIOS[u.escritorio].nome}
                    </div>
                  </div>
                </button>
              );
            })}
          </div>
        </div>

        <div style={{ marginTop:20, fontSize:11, color:"rgba(255,255,255,0.25)", textAlign:"center" }}>
          Acesso restrito a colaboradores internos do Grupo 3S
        </div>
      </div>
    </div>
  );

  // ═══════════════════════════════════════════════════════════════════════════
  // APP PRINCIPAL
  // ═══════════════════════════════════════════════════════════════════════════
  const abas = [
    { id:"nova",      label:"Nova Petição",      icon:"⚖" },
    { id:"banco",     label:"Banco de Prompts",  icon:"📋" },
    { id:"dashboard", label:"Dashboard",         icon:"📊" },
    ...(usuario?.perfil === "sócio" ? [{ id:"config", label:"Configurações", icon:"⚙" }] : [])
  ];

  return (
    <div style={{ minHeight:"100vh", background:"#f4f2ee", fontFamily:FONT_UI }}>

      {/* ── Header ─────────────────────────────────────────────────────────── */}
      <div style={{ background:"#0f1923", padding:"0 32px", display:"flex", alignItems:"center", justifyContent:"space-between", height:60, borderBottom:"2px solid #c8960c" }}>
        <div style={{ display:"flex", alignItems:"center", gap:16 }}>
          <span style={{ fontSize:22, fontWeight:700, color:"#fff", letterSpacing:-1, fontFamily:FONT_BODY }}>
            LEX<span style={{ color:"#c8960c" }}>IA</span>
          </span>
          <span style={{ fontSize:10, color:"#666", letterSpacing:3, textTransform:"uppercase" }}>Grupo 3S</span>
        </div>
        <div style={{ display:"flex", alignItems:"center", gap:12 }}>
          <div style={{ width:32, height:32, borderRadius:"50%", background:escInfo.cor,
            display:"flex", alignItems:"center", justifyContent:"center", color:"#fff", fontSize:11, fontWeight:700 }}>
            {usuario?.nome.split(" ").map(n=>n[0]).join("").slice(0,2)}
          </div>
          <div>
            <div style={{ fontSize:13, color:"#fff", fontWeight:600 }}>{usuario?.nome}</div>
            <div style={{ fontSize:10, color:"#aaa", textTransform:"capitalize" }}>{usuario?.perfil}</div>
          </div>
          <button onClick={() => setTela("login")} style={{ marginLeft:12, background:"none", border:"1px solid #333", borderRadius:6, padding:"4px 12px", color:"#aaa", fontSize:11, cursor:"pointer" }}>Sair</button>
        </div>
      </div>

      {/* ── Abas ───────────────────────────────────────────────────────────── */}
      <div style={{ background:"#fff", borderBottom:"1px solid #e0ddd5", padding:"0 32px", display:"flex" }}>
        {abas.map(a => (
          <button key={a.id} onClick={() => setAba(a.id)} style={{
            padding:"14px 20px", border:"none", background:"none", cursor:"pointer",
            fontSize:13, fontFamily:FONT_UI, color: aba===a.id ? "#0f1923":"#999",
            borderBottom: aba===a.id ? "2px solid #c8960c":"2px solid transparent",
            fontWeight: aba===a.id ? 600 : 400
          }}>{a.icon} {a.label}</button>
        ))}
      </div>

      <div style={{ maxWidth:1100, margin:"0 auto", padding:"32px 24px" }}>

        {/* ═══ ABA: NOVA PETIÇÃO ══════════════════════════════════════════════ */}
        {aba === "nova" && (
          <div>
            {/* ── Formulário ── */}
            {etapa === "form" && (
              <div style={{ display:"grid", gridTemplateColumns:"1fr 340px", gap:24 }}>

                <div style={{ background:"#fff", borderRadius:12, border:"1px solid #e0ddd5", padding:32 }}>
                  <div style={{ fontSize:18, fontWeight:700, color:"#0f1923", marginBottom:24, borderBottom:"2px solid #c8960c", paddingBottom:12, fontFamily:FONT_BODY }}>
                    Nova Peça Processual
                  </div>

                  {/* Escritório */}
                  <label style={{ fontSize:11, color:"#666", letterSpacing:1, textTransform:"uppercase", display:"block", marginBottom:8 }}>Escritório</label>
                  <div style={{ display:"flex", gap:10, marginBottom:20 }}>
                    {Object.entries(ESCRITORIOS).map(([k,info]) => (
                      <button key={k} onClick={() => setEscritorio(k)} style={{
                        flex:1, padding:"10px 16px", border: escritorio===k ? `2px solid \${info.cor}`:"1.5px solid #ddd",
                        borderRadius:8, background: escritorio===k ? info.cor:"#fafafa",
                        color: escritorio===k ? "#fff":"#444", cursor:"pointer", fontSize:14, fontWeight:600, fontFamily:FONT_UI
                      }}>{info.nome}</button>
                    ))}
                  </div>

                  {/* Processo */}
                  <label style={{ fontSize:11, color:"#666", letterSpacing:1, textTransform:"uppercase", display:"block", marginBottom:6 }}>Número do Processo</label>
                  <input value={numProcesso} onChange={e=>setNumProcesso(e.target.value)}
                    placeholder="0000000-00.0000.0.00.0000"
                    style={{ width:"100%", padding:"10px 14px", border:"1.5px solid #ddd", borderRadius:8, fontSize:14, fontFamily:FONT_UI, boxSizing:"border-box", marginBottom:16 }}/>

                  {/* Partes */}
                  <div style={{ display:"grid", gridTemplateColumns:"1fr 1fr", gap:12, marginBottom:16 }}>
                    {[["Parte Autora","Nome do(a) cliente",parteAutora,setParteAutora],
                      ["Parte Ré","Empresa / Réu",parteRe,setParteRe]].map(([lbl,ph,val,set]) => (
                      <div key={lbl}>
                        <label style={{ fontSize:11, color:"#666", letterSpacing:1, textTransform:"uppercase", display:"block", marginBottom:6 }}>{lbl}</label>
                        <input value={val} onChange={e=>set(e.target.value)} placeholder={ph}
                          style={{ width:"100%", padding:"10px 14px", border:"1.5px solid #ddd", borderRadius:8, fontSize:13, fontFamily:FONT_UI, boxSizing:"border-box" }}/>
                      </div>
                    ))}
                  </div>

                  {/* Tipo + Matéria */}
                  <div style={{ display:"grid", gridTemplateColumns:"1fr 1fr", gap:12, marginBottom:16 }}>
                    {[["Tipo de Peça",TIPOS_PECA,tipoPeca,setTipoPeca],
                      ["Matéria",MATERIAS,materia,setMateria]].map(([lbl,opts,val,set]) => (
                      <div key={lbl}>
                        <label style={{ fontSize:11, color:"#666", letterSpacing:1, textTransform:"uppercase", display:"block", marginBottom:6 }}>{lbl}</label>
                        <select value={val} onChange={e=>set(e.target.value)}
                          style={{ width:"100%", padding:"10px 14px", border:"1.5px solid #ddd", borderRadius:8, fontSize:13, fontFamily:FONT_UI, background:"#fff" }}>
                          <option value="">Selecione...</option>
                          {opts.map(o=><option key={o}>{o}</option>)}
                        </select>
                      </div>
                    ))}
                  </div>

                  {/* Upload */}
                  <label style={{ fontSize:11, color:"#666", letterSpacing:1, textTransform:"uppercase", display:"block", marginBottom:6 }}>Documentos do Processo (PDF/DOCX)</label>
                  <div onClick={()=>fileRef.current?.click()} style={{
                    border:"2px dashed #ccc", borderRadius:8, padding:14, textAlign:"center",
                    cursor:"pointer", background:"#fafafa", fontSize:13, color:"#888", marginBottom:16
                  }}>
                    {arquivos.length > 0 ? `\${arquivos.length} arquivo(s) selecionado(s)` : "Clique para anexar decisões, despachos, certidões, petições da parte contrária..."}
                  </div>
                  <input ref={fileRef} type="file" multiple accept=".pdf,.docx" style={{display:"none"}}
                    onChange={e=>setArquivos(Array.from(e.target.files))}/>

                  {/* Prompt */}
                  <div style={{ display:"flex", justifyContent:"space-between", alignItems:"center", marginBottom:6 }}>
                    <label style={{ fontSize:11, color:"#666", letterSpacing:1, textTransform:"uppercase" }}>Contexto e Instruções</label>
                    <div style={{ display:"flex", gap:8 }}>
                      <button onClick={sugerirPrompt} style={{ fontSize:11, background:"#f0ede5", border:"1px solid #ddd", borderRadius:6, padding:"3px 10px", cursor:"pointer", color:"#555", fontFamily:FONT_UI }}>💡 Prompt sugerido</button>
                      <button onClick={()=>setModoGuiado(!modoGuiado)} style={{ fontSize:11, background:modoGuiado?"#0f1923":"#f0ede5", border:"1px solid #ddd", borderRadius:6, padding:"3px 10px", cursor:"pointer", color:modoGuiado?"#fff":"#555", fontFamily:FONT_UI }}>🧭 Modo guiado</button>
                    </div>
                  </div>

                  {modoGuiado && (
                    <div style={{ background:"#fffbef", border:"1px solid #e8d87a", borderRadius:8, padding:14, marginBottom:10, fontSize:13, color:"#5a4a00", lineHeight:1.7, fontFamily:FONT_UI }}>
                      <strong>Passo a passo para uma boa {tipoPeca || "peça"}:</strong><br/>
                      1️⃣ <strong>Fatos:</strong> O que aconteceu? Datas, produtos/serviços envolvidos.<br/>
                      2️⃣ <strong>Alegação da parte contrária:</strong> O que a empresa/réu diz na contestação/decisão?<br/>
                      3️⃣ <strong>Provas disponíveis:</strong> Contratos, boletos, prints, laudos, documentos anexados.<br/>
                      4️⃣ <strong>Objetivo:</strong> O que você quer obter com esta peça?<br/>
                      5️⃣ <strong>Jurisprudência:</strong> Se souber de súmula ou tese aplicável, informe o número. Caso contrário, deixe em branco — a IA alertará para pesquisar.
                    </div>
                  )}

                  <textarea value={descricao} onChange={e=>setDescricao(e.target.value)} rows={6}
                    placeholder="Descreva os fatos, a situação processual, o que a parte contrária alega e o resultado pretendido. Não inclua jurisprudências sem ter certeza do número e enunciado corretos."
                    style={{ width:"100%", padding:"12px 14px", border:"1.5px solid #ddd", borderRadius:8, fontSize:14, fontFamily:FONT_UI, lineHeight:1.6, resize:"vertical", boxSizing:"border-box", marginBottom:8 }}/>

                  {/* Aviso sobre jurisprudência */}
                  <div style={{ background:"#fff8f0", border:"1px solid #f0c070", borderRadius:8, padding:"10px 14px", marginBottom:12, fontSize:12, color:"#7a4a00", lineHeight:1.6 }}>
                    ⚠️ <strong>Atenção — Jurisprudência:</strong> A IA nunca inventará números de processos ou acórdãos. Se sugerir citação jurisprudencial, ela indicará onde pesquisar (STJ/STF/TJAM). Sempre verifique antes de protocolar a peça.
                  </div>

                  {descricao.length > 10 && <QualityBadge {...avaliarPrompt(descricao)} />}

                  {alertaLider && (
                    <div style={{ background:"#fff3cd", border:"1px solid #f0a500", borderRadius:8, padding:14, marginTop:12, fontSize:13, color:"#7a4e00", lineHeight:1.7 }}>
                      ⚠️ <strong>Contexto insuficiente.</strong> Antes de prosseguir, consulte seu líder direto ou um dos sócios (Nicolas Gomes / Luis Albert) para alinhar as informações necessárias a uma peça de qualidade.
                      <br/><button onClick={()=>setAlertaLider(false)} style={{ marginTop:8, fontSize:11, background:"#fff", border:"1px solid #f0a500", borderRadius:6, padding:"3px 10px", cursor:"pointer", fontFamily:FONT_UI }}>Entendido — vou melhorar o contexto</button>
                    </div>
                  )}

                  <button onClick={gerarPeca} style={{
                    width:"100%", padding:"14px", background:"#0f1923", color:"#fff", border:"none",
                    borderRadius:10, fontSize:15, fontWeight:700, cursor:"pointer", fontFamily:FONT_BODY,
                    borderBottom:"3px solid #c8960c", marginTop:16
                  }}>⚖ Gerar Peça com IA</button>
                </div>

                {/* Painel lateral */}
                <div style={{ display:"flex", flexDirection:"column", gap:16 }}>
                  <div style={{ background:"#fff", borderRadius:12, border:"1px solid #e0ddd5", padding:20 }}>
                    <div style={{ fontSize:13, fontWeight:700, color:"#0f1923", marginBottom:12, borderLeft:"3px solid #c8960c", paddingLeft:10 }}>O que a IA faz</div>
                    {[
                      ["📄","Lê processos","Decisões, despachos e certidões (Projudi, PJe)"],
                      ["🔍","Pesquisa jurisprudência","Sugere onde buscar — nunca inventa referências"],
                      ["⚖","Aplica timbrado","DOCX com formatação NGADV ou LAADV"],
                      ["🗺","Mapa de tese","Pontos fortes e fracos da sua argumentação"],
                      ["🔗","Integra ao LEX FLOW","Carrega dados do processo automaticamente"],
                    ].map(([ic,t,d]) => (
                      <div key={t} style={{ display:"flex", gap:10, marginBottom:12 }}>
                        <span style={{ fontSize:17 }}>{ic}</span>
                        <div>
                          <div style={{ fontSize:13, fontWeight:600, color:"#1a1a1a" }}>{t}</div>
                          <div style={{ fontSize:11, color:"#888" }}>{d}</div>
                        </div>
                      </div>
                    ))}
                  </div>

                  <div style={{ background:"#0f1923", borderRadius:12, padding:20 }}>
                    <div style={{ fontSize:11, color:"#c8960c", fontWeight:700, marginBottom:8, letterSpacing:1, textTransform:"uppercase" }}>Produção hoje</div>
                    <div style={{ fontSize:32, fontWeight:700, color:"#fff" }}>7</div>
                    <div style={{ fontSize:12, color:"#888" }}>peças geradas no escritório</div>
                    <div style={{ marginTop:12, height:1, background:"#2a3a4a" }}/>
                    <div style={{ fontSize:11, color:"#c8960c", fontWeight:700, marginTop:12, marginBottom:8, letterSpacing:1, textTransform:"uppercase" }}>Alertas</div>
                    <div style={{ fontSize:12, color:"#ffd580", marginBottom:4 }}>⚠ 3 emendas à inicial pendentes</div>
                    <div style={{ fontSize:12, color:"#aaa" }}>✓ Nenhum prazo crítico hoje</div>
                  </div>

                  <div style={{ background:"#fff", borderRadius:12, border:"1px solid #e0ddd5", padding:20 }}>
                    <div style={{ fontSize:13, fontWeight:700, color:"#0f1923", marginBottom:12, borderLeft:"3px solid #c8960c", paddingLeft:10 }}>Timbrado ativo</div>
                    <img src={escInfo.logo} alt={escInfo.nome} style={{ width:"100%", maxHeight:56, objectFit:"contain" }}/>
                  </div>
                </div>
              </div>
            )}

            {/* ── Gerando ── */}
            {etapa === "gerando" && (
              <div ref={resultRef} style={{ background:"#fff", borderRadius:12, border:"1px solid #e0ddd5", padding:56, textAlign:"center" }}>
                <div style={{ fontSize:38, marginBottom:14 }}>⚖</div>
                <div style={{ fontSize:20, fontWeight:700, color:"#0f1923", marginBottom:8, fontFamily:FONT_BODY }}>Elaborando {tipoPeca}...</div>
                <div style={{ fontSize:13, color:"#888", marginBottom:28, maxWidth:500, margin:"0 auto 28px" }}>
                  A IA está analisando o contexto, verificando a legislação aplicável e redigindo a peça com o timbrado {escInfo.nome}. Jurisprudências só serão citadas se houver certeza absoluta — caso contrário, indicará onde pesquisar.
                </div>
                <div style={{ display:"flex", gap:8, justifyContent:"center", flexWrap:"wrap" }}>
                  {["Analisando contexto","Verificando legislação","Redigindo a peça","Aplicando formatação Cambria"].map((s,i) => (
                    <div key={i} style={{ padding:"6px 14px", background:"#f0ede5", borderRadius:20, fontSize:12, color:"#666", opacity:0.6+i*0.1 }}>{s}</div>
                  ))}
                </div>
              </div>
            )}

            {/* ── Resultado ── */}
            {etapa === "resultado" && (
              <div ref={resultRef}>
                <div style={{ display:"grid", gridTemplateColumns:"1fr 1fr", gap:20, marginBottom:20 }}>
                  {/* Parecer */}
                  <div style={{ background:"#fffbef", borderRadius:12, border:"1px solid #e8d87a", padding:24 }}>
                    <div style={{ fontSize:14, fontWeight:700, color:"#5a4a00", marginBottom:12, fontFamily:FONT_BODY }}>📋 Parecer Jurídico da IA</div>
                    <div style={{ fontSize:13, color:"#444", lineHeight:1.8, whiteSpace:"pre-wrap", fontFamily:FONT_UI }}>{parecerIA}</div>
                  </div>

                  {/* Mapa de tese */}
                  <div style={{ background:"#fff", borderRadius:12, border:"1px solid #e0ddd5", padding:24 }}>
                    <div style={{ fontSize:14, fontWeight:700, color:"#0f1923", marginBottom:12, fontFamily:FONT_BODY }}>🗺 Análise de Tese</div>
                    {[
                      { label:"Fundamentação legal",      status:"forte",  desc:"CDC e legislação aplicável verificados" },
                      { label:"Jurisprudência sugerida",  status:"atenção",desc:"Verifique no portal do tribunal antes de inserir" },
                      { label:"Provas documentais",       status: arquivos.length>0?"forte":"atenção", desc: arquivos.length>0?`\${arquivos.length} doc(s) anexado(s)`:"Nenhum documento anexado" },
                      { label:"Nexo causal",              status:"médio",  desc:"Depende dos fatos narrados" },
                    ].map(item => {
                      const c = {forte:"#1a6e32",médio:"#8a5e00",atenção:"#8a1a1a"};
                      const bg= {forte:"#eafaf0",médio:"#fff9e6",atenção:"#fdf0f0"};
                      return (
                        <div key={item.label} style={{ display:"flex", alignItems:"center", gap:10, padding:"8px 12px", background:bg[item.status], borderRadius:6, marginBottom:6 }}>
                          <div style={{ width:8, height:8, borderRadius:"50%", background:c[item.status], flexShrink:0 }}/>
                          <div>
                            <div style={{ fontSize:12, fontWeight:600, color:c[item.status] }}>{item.label}</div>
                            <div style={{ fontSize:11, color:"#666" }}>{item.desc}</div>
                          </div>
                        </div>
                      );
                    })}
                  </div>
                </div>

                {/* Peça formatada */}
                <div style={{ background:"#fff", borderRadius:12, border:"2px solid #0f1923", overflow:"hidden" }}>
                  <div style={{ background:"#0f1923", padding:"12px 24px", display:"flex", alignItems:"center", justifyContent:"space-between" }}>
                    <div style={{ display:"flex", alignItems:"center", gap:10 }}>
                      <img src={escInfo.logo} alt={escInfo.nome} style={{ height:26, objectFit:"contain" }}/>
                      <span style={{ color:"#c8960c", fontSize:13, fontWeight:600 }}>{tipoPeca} · Processo {numProcesso||"s/n"}</span>
                    </div>
                    <div style={{ display:"flex", gap:8 }}>
                      <button onClick={resetForm} style={{ fontSize:12, background:"#2a3a4a", border:"1px solid #444", borderRadius:6, padding:"5px 14px", color:"#aaa", cursor:"pointer", fontFamily:FONT_UI }}>← Nova Peça</button>
                      <button onClick={()=>alert("O DOCX com timbrado completo e formatação Cambria será gerado pelo módulo de exportação.")} style={{ fontSize:12, background:"#c8960c", border:"none", borderRadius:6, padding:"5px 14px", color:"#fff", cursor:"pointer", fontWeight:600, fontFamily:FONT_UI }}>⬇ Baixar DOCX</button>
                    </div>
                  </div>
                  <div style={{ padding:"32px 48px" }}>
                    <div style={{ borderBottom:"1px solid #e0ddd5", paddingBottom:16, marginBottom:24, textAlign:"center" }}>
                      <img src={escInfo.logo} alt={escInfo.nome} style={{ height:50, objectFit:"contain" }}/>
                    </div>
                    {/* Aviso de jurisprudência no resultado */}
                    <div style={{ background:"#fff8f0", border:"1px solid #f0c070", borderRadius:6, padding:"8px 14px", marginBottom:20, fontSize:12, color:"#7a4a00" }}>
                      📌 Antes de protocolar: verifique qualquer indicação jurisprudencial no portal do STJ (<a href="https://www.stj.jus.br" target="_blank" style={{color:"#7a4a00"}}>stj.jus.br</a>), STF ou tribunal competente. A IA não inventa referências, mas você deve confirmar as citações.
                    </div>
                    <div style={{
                      fontSize:12, fontFamily:'"Cambria", "Times New Roman", serif', lineHeight:1.8, color:"#1a1a1a",
                      whiteSpace:"pre-wrap", paddingLeft:"3cm", paddingRight:"2cm", textAlign:"justify"
                    }}>{pecaGerada}</div>
                  </div>
                </div>
              </div>
            )}
          </div>
        )}

        {/* ═══ ABA: BANCO DE PROMPTS ══════════════════════════════════════════ */}
        {aba === "banco" && (
          <div>
            <div style={{ fontSize:18, fontWeight:700, color:"#0f1923", marginBottom:6, fontFamily:FONT_BODY }}>Banco de Prompts</div>
            <div style={{ fontSize:13, color:"#888", marginBottom:24 }}>Prompts pré-validados. Clique para usar na elaboração de uma nova peça.</div>
            <div style={{ display:"grid", gridTemplateColumns:"repeat(auto-fill, minmax(420px,1fr))", gap:16 }}>
              {BANCO_PROMPTS.map((p,i) => (
                <div key={i} style={{ background:"#fff", borderRadius:12, border:"1px solid #e0ddd5", padding:24 }}>
                  <div style={{ display:"flex", gap:8, marginBottom:10 }}>
                    <span style={{ background:"#0f1923", color:"#c8960c", fontSize:11, fontWeight:700, borderRadius:4, padding:"3px 8px" }}>{p.tipo}</span>
                    <span style={{ background:"#f0ede5", color:"#666", fontSize:11, borderRadius:4, padding:"3px 8px" }}>{p.materia}</span>
                  </div>
                  <div style={{ fontSize:12, color:"#555", lineHeight:1.7, fontFamily:'"Cambria","Georgia",serif', marginBottom:12 }}>
                    {p.prompt.slice(0,200)}...
                  </div>
                  <button onClick={() => { setAba("nova"); setTipoPeca(p.tipo); setMateria(p.materia); setDescricao(p.prompt); setEtapa("form"); }}
                    style={{ fontSize:12, background:"#0f1923", color:"#fff", border:"none", borderRadius:6, padding:"6px 16px", cursor:"pointer", fontFamily:FONT_UI }}>
                    Usar este prompt →
                  </button>
                </div>
              ))}
            </div>
          </div>
        )}

        {/* ═══ ABA: DASHBOARD ═════════════════════════════════════════════════ */}
        {aba === "dashboard" && (
          <div>
            <div style={{ fontSize:18, fontWeight:700, color:"#0f1923", marginBottom:24, fontFamily:FONT_BODY }}>Dashboard de Produtividade</div>
            <div style={{ display:"grid", gridTemplateColumns:"repeat(4,1fr)", gap:16, marginBottom:28 }}>
              {[["⚖","Peças este mês",66],["⏱","Tempo médio","52min"],["⚠","Emendas à inicial",10],["👥","Usuários ativos",4]].map(([ic,lb,vl]) => (
                <div key={lb} style={{ background:"#fff", borderRadius:12, border:"1px solid #e0ddd5", padding:20 }}>
                  <div style={{ fontSize:22, marginBottom:4 }}>{ic}</div>
                  <div style={{ fontSize:28, fontWeight:700, color:"#0f1923", fontFamily:FONT_BODY }}>{vl}</div>
                  <div style={{ fontSize:12, color:"#888" }}>{lb}</div>
                </div>
              ))}
            </div>

            <div style={{ background:"#fff", borderRadius:12, border:"1px solid #e0ddd5", overflow:"hidden", marginBottom:24 }}>
              <div style={{ background:"#0f1923", padding:"14px 24px" }}>
                <span style={{ color:"#fff", fontSize:14, fontWeight:600 }}>Produção por Colaborador</span>
              </div>
              <table style={{ width:"100%", borderCollapse:"collapse" }}>
                <thead>
                  <tr style={{ borderBottom:"1px solid #e0ddd5" }}>
                    {["Colaborador","Peças geradas","Tempo médio","Emendas","Principais matérias"].map(h=>(
                      <th key={h} style={{ padding:"12px 16px", textAlign:"left", fontSize:12, color:"#888", fontWeight:600, fontFamily:FONT_UI }}>{h}</th>
                    ))}
                  </tr>
                </thead>
                <tbody>
                  {DASHBOARD_DATA.map((r,i) => (
                    <tr key={i} style={{ borderBottom:"1px solid #f0ede5" }}>
                      <td style={{ padding:"12px 16px", fontSize:13, fontWeight:600 }}>{r.usuario}</td>
                      <td style={{ padding:"12px 16px" }}><span style={{ background:"#eafaf0", color:"#1a6e32", borderRadius:12, padding:"3px 10px", fontSize:12, fontWeight:600 }}>{r.pecas}</span></td>
                      <td style={{ padding:"12px 16px", fontSize:13, color:"#555" }}>{r.tempoMedio}</td>
                      <td style={{ padding:"12px 16px" }}><span style={{ background:r.emendas>2?"#fdf0f0":"#f0ede5", color:r.emendas>2?"#8a1a1a":"#555", borderRadius:12, padding:"3px 10px", fontSize:12 }}>{r.emendas}</span></td>
                      <td style={{ padding:"12px 16px", fontSize:12, color:"#666" }}>{r.materias.join(" · ")}</td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>

            <div style={{ background:"#fff", borderRadius:12, border:"1px solid #e0ddd5", padding:24 }}>
              <div style={{ fontSize:14, fontWeight:700, color:"#0f1923", marginBottom:16, borderLeft:"3px solid #f0a500", paddingLeft:10, fontFamily:FONT_BODY }}>
                ⚠ Emendas à Inicial Pendentes
              </div>
              {[
                { proc:"0017392-55.2024.8.04.0001", colab:"Pedro Lima",   data:"22/05/2026", det:"Juntar comprovante de residência e CPF" },
                { proc:"0043211-08.2024.8.04.0001", colab:"Julia Mendes", data:"20/05/2026", det:"Corrigir valor da causa" },
                { proc:"0088103-21.2025.8.19.0001", colab:"Pedro Lima",   data:"19/05/2026", det:"Especificar pedido de tutela antecipada" },
              ].map((e,i) => (
                <div key={i} style={{ display:"flex", alignItems:"center", gap:16, padding:"12px 0", borderBottom:"1px solid #f0ede5" }}>
                  <div style={{ width:8, height:8, borderRadius:"50%", background:"#f0a500", flexShrink:0 }}/>
                  <div style={{ flex:1 }}>
                    <div style={{ fontSize:13, fontWeight:600, color:"#1a1a1a", fontFamily:'"Cambria","Georgia",serif' }}>{e.proc}</div>
                    <div style={{ fontSize:12, color:"#888" }}>{e.det}</div>
                  </div>
                  <div style={{ fontSize:11, color:"#aaa" }}>{e.colab} · {e.data}</div>
                </div>
              ))}
            </div>
          </div>
        )}

        {/* ═══ ABA: CONFIGURAÇÕES ═════════════════════════════════════════════ */}
        {aba === "config" && usuario?.perfil === "sócio" && (
          <div style={{ background:"#fff", borderRadius:12, border:"1px solid #e0ddd5", padding:32 }}>
            <div style={{ fontSize:18, fontWeight:700, color:"#0f1923", marginBottom:24, fontFamily:FONT_BODY }}>Configurações da Plataforma</div>
            {[
              { t:"Integração LEX FLOW",    d:"Conectar ao sistema interno de gestão de processos",       s:"pendente" },
              { t:"Projudi / PJe",          d:"Autenticação para leitura automática de processos",         s:"pendente" },
              { t:"Gestão de usuários",     d:"Adicionar, remover e definir perfis de acesso",             s:"ativo" },
              { t:"Timbrados",              d:"Atualizar logos e informações dos escritórios",             s:"ativo" },
              { t:"Banco de prompts",       d:"Adicionar e validar novos prompts para a equipe",           s:"ativo" },
              { t:"Regras de jurisprudência",d:"Controlar quando a IA sugere pesquisa jurisprudencial",   s:"ativo" },
            ].map((item,i) => (
              <div key={i} style={{ display:"flex", alignItems:"center", gap:16, padding:"16px 0", borderBottom:"1px solid #f0ede5" }}>
                <div style={{ flex:1 }}>
                  <div style={{ fontSize:14, fontWeight:600, color:"#1a1a1a" }}>{item.t}</div>
                  <div style={{ fontSize:12, color:"#888" }}>{item.d}</div>
                </div>
                <span style={{ fontSize:11, fontWeight:600, borderRadius:12, padding:"4px 12px",
                  background:item.s==="ativo"?"#eafaf0":"#fff9e6",
                  color:item.s==="ativo"?"#1a6e32":"#8a5e00" }}>{item.s}</span>
              </div>
            ))}
          </div>
        )}

      </div>
    </div>
  );
}
